def run_code(code, global_env):
    buffer = io.StringIO()
    try:
        # Redirect stdout so print() goes to the buffer
        with contextlib.redirect_stdout(buffer):
            exec(code, global_env)
    except Exception as e:
        # If it crashes, grab the traceback and return it
        err_msg = f"Error: {e}\n{traceback.format_exc()}"
        return err_msg
        
    return buffer.getvalue().strip()

def main():
    global_env = {}
    
    # Pre-inject all the data science libraries
    setup_code = """
import polars as pl
import pyarrow as pa
import pyarrow.parquet as pq
import pyarrow.compute as pc
import time
import os
import gc
import chess
import re
import numpy as np
import statistics
from collections import Counter
from sklearn.linear_model import SGDClassifier
"""
    exec(setup_code, global_env)

    print(f"Starting execution of {len(qa_data)} questions...\\n")

    # 1. Initialize the markdown file (overwrite if it exists)
    with open("output.md", "w", encoding="utf-8") as f:
        f.write("# Kérdések és válaszok\n\n")

    for i, (question, code) in enumerate(qa_data, 1):
        print(f"[{i}/{len(qa_data)}] Executing: {question[:50]}...")
        
        answer = run_code(code, global_env)
        
        if answer.startswith("Error:"):
            print(f" -> [!] FAILED. Saved error to output.md.")
        else:
            print(f" -> [+] SUCCESS. Saved to output.md.")
            
        # 2. Append the result to the file IMMEDIATELY
        with open("output.md", "a", encoding="utf-8") as f:
            f.write(f"{i}. {question}\n\n")
            f.write("```\n")
            f.write(f"{answer}\n")
            f.write("```\n\n")
            
    print("\\nAll tasks finished! Results have been saved to output.md")

if __name__ == "__main__":
    main()
